201	    // Context is required for every case execution path (rbtdrc_with_ctx).
202	    // Fixtures with a setup hook (crucible charge) additionally verify their
203	    // crucible is charged externally — single-case mode never charges.
204	    let mut ctx = rbtdri_Context::new(
205	        &project_root,
206	        fixture,
207	        &roots.burv_temp_root,
208	        &roots.burv_output_root,
209	    );
