211	    let fixture_def = match rbtdrc_lookup_fixture(fixture) {
212	        Some(f) => f,
213	        None => rbtd::rbtdrg_fatal_now!(
214	            "rbtd single: fixture '{}' has no registered Fixture",
215	            fixture
216	        ),
217	    };
218	
219	    if fixture_def.setup.is_some() {
220	        match rbtdri_invoke_global(
221	            &mut ctx,
222	            RBTDRM_COLOPHON_CRUCIBLE_ACTIVE,
223	            &[fixture],
224	            &[],
225	        ) {
226	            Ok(r) if r.exit_code == 0 => {}
