241	        None => {
242	            rbtdre_list_cases(cases);
243	            return ExitCode::SUCCESS;
244	        }
245	        Some(n) => n,
246	    };
247	
248	    // Find the case
249	    let case = match rbtdre_find_case(cases, case_name) {
250	        Some(c) => c,
251	        None => {
252	            rbtd::rbtdrg_error_now!(
253	                "rbtd single: case '{}' not found in fixture '{}'",
254	                case_name, fixture
255	            );
256	            rbtdre_list_cases(cases);
257	            return ExitCode::FAILURE;
258	        }
259	    };
260	
261	    let colors = rbtdre_detect_colors();
262	    let result = match rbtdre_run_single_case(case, &colors, &roots.trace_root) {
263	        Ok(r) => r,
