208	// ── Tabtarget invocation with BURV isolation ─────────────────
209	
210	/// Internal: execute a resolved tabtarget with BURV isolation and optional extra env vars.
211	fn rbtdri_invoke_impl(
212	    ctx: &mut rbtdri_Context,
213	    tabtarget: &Path,
214	    args: &[&str],
215	    extra_env: &[(&str, &str)],
216	) -> Result<rbtdri_InvokeResult, String> {
217	    let invoke_num = ctx.invoke_count;
218	    ctx.invoke_count += 1;
219	
220	    let dir_name = rbtdri_invoke_dir_name(invoke_num);
221	    let burv_output = ctx.burv_output_root.join(&dir_name);
222	    let burv_temp = ctx.burv_temp_root.join(&dir_name);
223	
224	    std::fs::create_dir_all(&burv_output)
225	        .map_err(|e| format!("rbtdri: failed to create BURV output dir: {}", e))?;
226	    std::fs::create_dir_all(&burv_temp)
227	        .map_err(|e| format!("rbtdri: failed to create BURV temp dir: {}", e))?;
228	
229	    let mut cmd = Command::new(tabtarget);
230	    cmd.args(args)
231	        .current_dir(&ctx.project_root)
232	        .env("BURV_OUTPUT_ROOT_DIR", &burv_output)
233	        .env("BURV_TEMP_ROOT_DIR", &burv_temp);
234	
235	    for (key, value) in extra_env {
236	        cmd.env(key, value);
237	    }
238	
239	    let output = cmd
240	        .output()
241	        .map_err(|e| format!("rbtdri: failed to execute '{}': {}", tabtarget.display(), e))?;
242	
243	    Ok(rbtdri_InvokeResult {
244	        stdout: String::from_utf8_lossy(&output.stdout).into_owned(),
245	        stderr: String::from_utf8_lossy(&output.stderr).into_owned(),
246	        exit_code: output.status.code().unwrap_or(-1),
247	        burv_output,
248	    })
